  it.todo("should pay full amount for dragon material items");
  it.todo("should pay 50% for highly enchanted items (≥8)");
  it.todo("should round payout down (floor) to nearest G");
  it.todo("should reject claim for unknown item type");
  it.todo("should reject claim for item not in policy");
